@startuml

abstract class Expression

class Value {
  - int value
}

class Addition {
  - Expression& lhs
  - Expression& lhs
}

class Multiplication {
  - Expression& lhs
  - Expression& lhs
}

abstract class Visitor {
  + visit(Expression& expr)
}

class Printer {
  - stringstream oss
  + visit(Expression& expr)\n    if (auto de = dynamic_cast<Value&>(e))\n        oss << de.value\n    else if (auto ae = dynamic_cast<Addition&>(e))\n        visit(ae.left)\n        oss << "+"\n        visit(ae.right)\n    else if...
}

class Evaluator {
  - int total
  + visit(Expression& expr)
}

Value --|> Expression
Addition --|> Expression
Multiplication --|> Expression

Printer ..|> Value
Printer ..|> Addition
Printer ..|> Multiplication
Printer --> Visitor

Evaluator --|> Visitor

@enduml
